import ShowPasswordButton from "../ShowPasswordButton";

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  name: string;
  type: string;
  isPassword?: boolean;
}

export default function Input({
  name,
  type = "text",
  isPassword,
  ...props
}: InputProps) {
  return (
    <>
      <input
        className="bg-transparent border border-purple-400 rounded"
        style={{ position: isPassword ? "relative" : "inherit" }}
        id={name}
        name={name}
        type={type}
        {...props}
        required
      />
      
      {isPassword && <div>
        <ShowPasswordButton />
        </div>
        }
    </>
  );
}
